  /**
   * Verify hash chain continuity for a match's transaction log.
   * Each entry's stateHashBefore must equal the previous entry's stateHashAfter.
   */
  async verifyHashChain(matchId: string): Promise<{
    valid: boolean;
    actionCount: number;
    finalStateHash: string | null;
    error?: string;
    failedAtSequence?: number;
  }> {
    const database = db;
    if (!database)
      return {
        valid: false,
        actionCount: 0,
        finalStateHash: null,
        error: 'Database not available',
      };

    try {
      const rows = await traceDbQuery(
        'db.transaction_logs.select_hashes',
        { operation: 'SELECT', table: 'transaction_logs' },
        () =>
          database
            .select({
              sequenceNumber: transactionLogs.sequenceNumber,
              stateHashBefore: transactionLogs.stateHashBefore,
              stateHashAfter: transactionLogs.stateHashAfter,
            })
            .from(transactionLogs)
            .where(eq(transactionLogs.matchId, matchId))
            .orderBy(asc(transactionLogs.sequenceNumber)),
      );

      if (rows.length === 0) {
        return {
          valid: false,
          actionCount: 0,
          finalStateHash: null,
          error: 'No transaction log entries found',
        };
      }

      for (let i = 1; i < rows.length; i++) {
        const prev = rows[i - 1];
        const curr = rows[i];
        if (!prev || !curr) continue;
        if (curr.stateHashBefore !== prev.stateHashAfter) {
          return {
            valid: false,
            actionCount: rows.length,
            finalStateHash: null,
            error: `Hash chain break at sequence ${curr.sequenceNumber}: expected ${prev.stateHashAfter}, got ${curr.stateHashBefore}`,
            failedAtSequence: curr.sequenceNumber,
          };
        }
      }

      const finalHash = rows.at(-1)?.stateHashAfter ?? null;
      return { valid: true, actionCount: rows.length, finalStateHash: finalHash };
    } catch (err) {
      emitOtlpLog(SeverityNumber.ERROR, 'ERROR', 'Failed to verify hash chain', {
        'db.operation': 'verifyHashChain',
        'error.message': err instanceof Error ? err.message : String(err),
      });
      return { valid: false, actionCount: 0, finalStateHash: null, error: 'Database query failed' };
    }
  }

  async listRecentlyExpiredPublicMatches(windowMs = 60 * 60 * 1000): Promise<
    {
      matchId: string;
      creatorUserId: string | null;
      creatorName: string | null;
      publicExpiresAt: Date | null;
      createdAt: Date;
      minPublicRating: number | null;
      maxPublicRating: number | null;
      minGamesPlayed: number | null;
      requiresEstablishedRating: boolean;
    }[]
  > {
    const database = db;
    if (!database) return [];
    const cutoff = new Date(Date.now() - windowMs);
    try {
      const rows = await traceDbQuery(
        'db.matches.list_recently_expired',
        { operation: 'SELECT', table: 'matches' },
        () =>
          database
            .select({
              matchId: matches.id,
              creatorUserId: matches.player1Id,
              creatorName: matches.player1Name,
              publicExpiresAt: matches.publicExpiresAt,
              createdAt: matches.createdAt,
              minPublicRating: matches.minPublicRating,
              maxPublicRating: matches.maxPublicRating,
              minGamesPlayed: matches.minGamesPlayed,
              requiresEstablishedRating: matches.requiresEstablishedRating,
            })
            .from(matches)
            .where(
              and(
                eq(matches.visibility, 'public_open'),
                eq(matches.publicStatus, 'expired'),
                sql`${matches.publicExpiresAt} > ${cutoff}`,
              ),
            )
            .orderBy(desc(matches.publicExpiresAt)),
      );
      return rows;
    } catch (err) {
      emitOtlpLog(SeverityNumber.ERROR, 'ERROR', 'Failed to list recently expired matches', {
        'db.operation': 'listRecentlyExpiredPublicMatches',
        'error.message': err instanceof Error ? err.message : String(err),
