import { createHash } from 'node:crypto';
import { existsSync, readdirSync, readFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));

export const MIGRATIONS_DIR = resolve(__dirname, '../../migrations');
export const MIGRATIONS_TABLE = 'schema_migrations';

export interface MigrationFile {
  name: string;
  checksum: string;
  path: string;
  statements: string[];
}

function checksum(text: string): string {
  return createHash('sha256').update(text, 'utf8').digest('hex');
}

function splitStatements(sqlText: string): string[] {
  return sqlText
    .split('--> statement-breakpoint')
    .map((statement) => statement.trim())
    .filter(Boolean)
    .map((statement) => statement.replace(/;$/u, '').trim())
    .filter(Boolean);
}

export function loadMigrationFiles(): MigrationFile[] {
  if (!existsSync(MIGRATIONS_DIR)) {
    throw new Error(
      `Migrations directory not found: ${MIGRATIONS_DIR}. ` +
        'This likely means the build did not bundle the migrations folder alongside the compiled output.',
    );
  }

  const names = readdirSync(MIGRATIONS_DIR)
    .filter((entry) => entry.endsWith('.sql'))
    .sort((a, b) => a.localeCompare(b));

  if (names.length === 0) {
    throw new Error(
      `Migrations directory is empty: ${MIGRATIONS_DIR}. ` +
        'At least one migration file is required.',
    );
  }

  return names.map((name) => {
    const path = resolve(MIGRATIONS_DIR, name);
    const contents = readFileSync(path, 'utf8');
    return {
      name,
      checksum: checksum(contents),
      path,
      statements: splitStatements(contents),
    };
  });
}

import './instrument.js';
import { buildApp } from './app.js';
import { checkPendingMigrations } from './db/check-migrations.js';
import { spawn } from 'node:child_process';
import { openSync } from 'node:fs';
import { resolve } from 'node:path';

// Intercept daemon flag before doing anything else
if (process.argv.includes('--daemon')) {
  const outLog = resolve(process.cwd(), 'phalanx-server.out.log');
  const errLog = resolve(process.cwd(), 'phalanx-server.err.log');
  const out = openSync(outLog, 'a');
  const err = openSync(errLog, 'a');

  // Strip "--daemon" to prevent infinite spawning loop
  const args = process.argv.slice(1).filter((arg) => arg !== '--daemon');

  const command: string = process.argv[0] ?? 'node';
  const child = spawn(command, args, {
    detached: true,
    stdio: ['ignore', out, err],
    env: process.env,
  });

  child.unref();
  console.log(`Phalanx Duel server started in daemon mode (PID: ${child.pid})`);
  console.log(`STDOUT -> ${outLog}`);
  console.log(`STDERR -> ${errLog}`);
  process.exit(0);
}

async function main(): Promise<void> {
  await checkPendingMigrations();
  let app = await buildApp();
  const port = parseInt(process.env.PHALANX_SERVER_PORT ?? '3001', 10);
  const host = process.env.HOST ?? '0.0.0.0';

  await app.listen({ port, host });
  console.log(`Phalanx Duel server listening on http://${host}:${port}`);

  // ── Graceful Shutdown Handler ────────────────────────────────────
  // When the container receives SIGTERM (Kubernetes, Docker stop, Fly.io deploy),
  // close the server gracefully, allowing in-flight requests/WebSocket connections
  // to complete within a timeout window.
  //
  // Timeline:
  // 1. Signal received → Stop accepting NEW connections
  // 2. Close server → Wait for in-flight requests (30s timeout)
  // 3. Exit → Process terminates, container restarts
  const shutdownSignals = ['SIGTERM', 'SIGINT', 'SIGQUIT'];
  const reloadSignals = ['SIGHUP', 'SIGUSR2'];

  shutdownSignals.forEach((signal) => {
    process.on(
      signal,
      () =>
        void (async () => {
          app.log.info(`Received ${signal}, initiating graceful shutdown...`);

          try {
            await app.close();
            app.log.info('Server closed successfully, all connections drained');
            process.exit(0);
          } catch (err) {
            app.log.error(
              { error: err instanceof Error ? err.message : String(err) },
              'Error during graceful shutdown',
            );
            process.exit(1);
          }
        })(),
    );
  });

  reloadSignals.forEach((signal) => {
    process.on(
      signal,
      () =>
        void (async () => {
          app.log.info(`Received ${signal}, initiating configuration reload...`);

          try {
            await app.close();
            app.log.info('Server closed. Reloading environment variables from configuration...');

            // Re-evaluate configuration manually
            const { loadAllEnvs } = await import('./loadEnv.js');
            loadAllEnvs();

            app = await buildApp();
            const port = parseInt(process.env.PHALANX_SERVER_PORT ?? '3001', 10);
            const host = process.env.HOST ?? '0.0.0.0';

            await app.listen({ port, host });
            app.log.info(`Phalanx Duel server re-listening on http://${host}:${port}`);
          } catch (err) {
            app.log.error(
              { error: err instanceof Error ? err.message : String(err) },
              'Error during configuration reload',
            );
            process.exit(1);
          }
        })(),
    );
  });

  // Handle uncaught exceptions → log and exit
  process.on('uncaughtException', (err) => {
    app.log.error(
      { error: err instanceof Error ? err.message : String(err) },
      'Uncaught exception, exiting',
    );
    process.exit(1);
  });

  // Handle unhandled promise rejections → log and exit
  process.on('unhandledRejection', (reason) => {
    app.log.error({ reason }, 'Unhandled rejection, exiting');
    process.exit(1);
  });
}

main().catch((err: unknown) => {
  console.error('Failed to start server:', err);
  process.exit(1);
});

import { and, desc, eq, count } from 'drizzle-orm';
import { db } from './db/index.js';
import { matchResults, matches, playerRatings, users, userFollows } from './db/schema.js';
import { traceDbQuery } from './db/observability.js';
import { ELO_CONSTANTS } from './elo.js';

export type RatingMode = 'pvp' | 'sp-random' | 'sp-heuristic';

export type PublicConfidenceLabel = 'Provisional' | 'Calibrating' | 'Established' | 'Inactive';

export interface PublicMatchEntry {
  matchId: string;
  result: 'win' | 'loss' | 'draw';
  mode: RatingMode;
  opponentName: string | null;
  completedAt: string;
  turnNumber: number | null;
}

export interface PublicChallengeEntry {
  matchId: string;
  createdAt: string;
  createdAtIso: string;
  creatorName: string;
  creatorElo: number;
  creatorRecord: {
    wins: number;
    losses: number;
    draws: number;
    gamesPlayed: number;
    provisional: boolean;
    confidenceLabel: PublicConfidenceLabel;
  };
  requirements: {
    minPublicRating: number | null;
    maxPublicRating: number | null;
    minGamesPlayed: number | null;
    requiresEstablishedRating: boolean;
  };
}

export interface PublicProfile {
  userId: string;
  gamertag: string;
  displayName: string;
  elo: number;
  record: {
    wins: number;
    losses: number;
    draws: number;
    gamesPlayed: number;
  };
  streak: number;
  confidenceLabel: PublicConfidenceLabel;
  recentMatches: PublicMatchEntry[];
  openChallenges: PublicChallengeEntry[];
  followStats?: {
    followers: number;
    following: number;
  };
  isFollowing?: boolean;
}

interface RatingRow {
  eloRating: number;
  glickoRating: number;
  glickoRatingDeviation: number;
  glickoVolatility: number;
  gamesPlayed: number;
  wins: number;
  losses: number;
  draws: number;
  abandons: number;
  provisional: boolean;
}

interface MatchOutcome {
  winnerIndex?: number | null;
  turnNumber?: number | null;
}

function modeFromBotStrategy(botStrategy: string | null | undefined): RatingMode {
  if (!botStrategy) return 'pvp';
  return `sp-${botStrategy}` as RatingMode;
}

function confidenceLabel(row: RatingRow | null, lastRatedAt: Date | null): PublicConfidenceLabel {
  if (!row) return 'Provisional';
  if (row.provisional) return 'Provisional';
  if (row.gamesPlayed < 10 || row.glickoRatingDeviation >= 220) return 'Calibrating';
  if (lastRatedAt && Date.now() - lastRatedAt.getTime() > 30 * 24 * 60 * 60 * 1000) {
    return 'Inactive';
  }
  return 'Established';
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function ratingDelta(currentElo: number, opponentElo: number, score: number): number {
  const expected = 1 / (1 + 10 ** ((opponentElo - currentElo) / 400));
  return Math.round(ELO_CONSTANTS.K_FACTOR * (score - expected));
}

function resultFromOutcome(
  winnerIndex: number | null | undefined,
  playerIndex: 0 | 1,
): 'win' | 'loss' | 'draw' {
  if (winnerIndex === null || winnerIndex === undefined || winnerIndex < 0) return 'draw';
  return winnerIndex === playerIndex ? 'win' : 'loss';
}

function scoreFromResult(result: 'win' | 'loss' | 'draw'): number {
  if (result === 'win') return 1;
  if (result === 'draw') return 0.5;
  return 0;
}

function buildDisplayName(gamertag: string, suffix: number | null): string {
  return suffix ? `${gamertag}#${suffix}` : gamertag;
}

export class PlayerRatingsService {
  private readonly database = db;

  async recordMatchComplete(match: {
    matchId: string;
    player1Id: string | null;
    player2Id: string | null;
    botStrategy: string | null | undefined;
    outcome: MatchOutcome | null;
    abandonPlayerIndex?: 0 | 1 | null;
  }): Promise<void> {
    const database = this.database;
    if (!database) return;

    const mode = modeFromBotStrategy(match.botStrategy);
    const participants: { userId: string; playerIndex: 0 | 1; opponentId: string | null }[] = [];
    if (match.player1Id)
      participants.push({ userId: match.player1Id, playerIndex: 0, opponentId: match.player2Id });
    if (match.player2Id)
      participants.push({ userId: match.player2Id, playerIndex: 1, opponentId: match.player1Id });
    if (participants.length === 0) return;

    await traceDbQuery('db.match_results.record', { operation: 'TX', table: 'match_results' }, () =>
      database.transaction(async (tx) => {
        for (const participant of participants) {
          const existing = await tx
            .select({ userId: matchResults.userId })
            .from(matchResults)
            .where(
              and(
                eq(matchResults.matchId, match.matchId),
                eq(matchResults.userId, participant.userId),
              ),
            )
            .limit(1);
          if (existing.length > 0) continue;

          const [currentRating] = await tx
            .select()
            .from(playerRatings)
            .where(and(eq(playerRatings.userId, participant.userId), eq(playerRatings.mode, mode)))
            .limit(1);

          const [userRow] = await tx
            .select({ id: users.id, elo: users.elo })
            .from(users)
            .where(eq(users.id, participant.userId))
            .limit(1);

          if (!userRow) {
            continue;
          }

          const [opponentRow] = participant.opponentId
            ? await tx
                .select({ id: users.id, elo: users.elo })
                .from(users)
                .where(eq(users.id, participant.opponentId))
                .limit(1)
            : [undefined];

          const row: RatingRow = currentRating
            ? {
                eloRating: currentRating.eloRating,
                glickoRating: currentRating.glickoRating,
                glickoRatingDeviation: currentRating.glickoRatingDeviation,
                glickoVolatility: currentRating.glickoVolatility,
                gamesPlayed: currentRating.gamesPlayed,
                wins: currentRating.wins,
                losses: currentRating.losses,
                draws: currentRating.draws,
                abandons: currentRating.abandons,
                provisional: currentRating.provisional,
              }
            : {
                eloRating: userRow?.elo ?? 1000,
                glickoRating: 1500,
                glickoRatingDeviation: 350,
                glickoVolatility: 0.06,
                gamesPlayed: 0,
                wins: 0,
                losses: 0,
                draws: 0,
                abandons: 0,
                provisional: true,
              };

          const result = resultFromOutcome(match.outcome?.winnerIndex, participant.playerIndex);
          const score = scoreFromResult(result);
          const opponentRating = opponentRow?.elo ?? row.eloRating;
          const eloDelta = ratingDelta(row.eloRating, opponentRating, score);
          const glickoDelta = Math.round(eloDelta * 1.5);
          const nextRow = {
            eloRating: row.eloRating + eloDelta,
            glickoRating: row.glickoRating + glickoDelta,
            glickoRatingDeviation: Math.max(80, Math.round(row.glickoRatingDeviation * 0.92)),
            glickoVolatility: clamp(
              row.glickoVolatility + (score === 1 ? -0.002 : score === 0 ? 0.002 : 0),
              0.03,
              0.12,
            ),
            gamesPlayed: row.gamesPlayed + 1,
            wins: row.wins + (result === 'win' ? 1 : 0),
            losses: row.losses + (result === 'loss' ? 1 : 0),
            draws: row.draws + (result === 'draw' ? 1 : 0),
            abandons: row.abandons + (match.abandonPlayerIndex === participant.playerIndex ? 1 : 0),
            provisional:
              row.gamesPlayed + 1 < 10 ||
              Math.max(80, Math.round(row.glickoRatingDeviation * 0.92)) >= 220,
          };

          await tx.insert(matchResults).values({
            matchId: match.matchId,
            userId: participant.userId,
            opponentId: participant.opponentId,
            mode,
            result,
            eloBefore: row.eloRating,
            eloAfter: nextRow.eloRating,
            eloDelta,
            glickoBefore: row.glickoRating,
            glickoAfter: nextRow.glickoRating,
            glickoRdBefore: row.glickoRatingDeviation,
            glickoRdAfter: nextRow.glickoRatingDeviation,
          });

          await tx
            .insert(playerRatings)
            .values({
              userId: participant.userId,
              mode,
              eloRating: nextRow.eloRating,
              glickoRating: nextRow.glickoRating,
              glickoRatingDeviation: nextRow.glickoRatingDeviation,
              glickoVolatility: nextRow.glickoVolatility,
              gamesPlayed: nextRow.gamesPlayed,
              wins: nextRow.wins,
              losses: nextRow.losses,
              draws: nextRow.draws,
              abandons: nextRow.abandons,
              provisional: nextRow.provisional,
              lastRatedAt: new Date(),
              updatedAt: new Date(),
            })
            .onConflictDoUpdate({
              target: [playerRatings.userId, playerRatings.mode],
              set: {
                eloRating: nextRow.eloRating,
                glickoRating: nextRow.glickoRating,
                glickoRatingDeviation: nextRow.glickoRatingDeviation,
                glickoVolatility: nextRow.glickoVolatility,
                gamesPlayed: nextRow.gamesPlayed,
                wins: nextRow.wins,
                losses: nextRow.losses,
                draws: nextRow.draws,
                abandons: nextRow.abandons,
                provisional: nextRow.provisional,
                lastRatedAt: new Date(),
                updatedAt: new Date(),
              },
            });

          await tx
            .update(users)
            .set({
              elo: nextRow.eloRating,
              updatedAt: new Date(),
            })
            .where(eq(users.id, participant.userId));
        }
      }),
    );
  }

  async getCreatorStats(userId: string): Promise<{
    eloRating: number;
    glickoRating: number;
    glickoRD: number;
    wins: number;
    losses: number;
    abandons: number;
    gamesPlayed: number;
    matchesCreated: number;
    successfulStarts: number;
  } | null> {
    const database = this.database;
    if (!database) return null;
    const [userRow] = await traceDbQuery(
      'db.users.select_creator_stats',
      { operation: 'SELECT', table: 'users' },
      () =>
        database
          .select({
            elo: users.elo,
            matchesCreated: users.matchesCreated,
            successfulStarts: users.successfulStarts,
          })
          .from(users)
          .where(eq(users.id, userId))
          .limit(1),
    );
    if (!userRow) return null;
    const [ratingRow] = await traceDbQuery(
      'db.player_ratings.select_creator_stats',
      { operation: 'SELECT', table: 'player_ratings' },
      () =>
        database
          .select()
          .from(playerRatings)
          .where(and(eq(playerRatings.userId, userId), eq(playerRatings.mode, 'pvp')))
          .limit(1),
    );
    return {
      eloRating: ratingRow?.eloRating ?? userRow.elo,
      glickoRating: ratingRow?.glickoRating ?? 1500,
      glickoRD: ratingRow?.glickoRatingDeviation ?? 350,
      wins: ratingRow?.wins ?? 0,
      losses: ratingRow?.losses ?? 0,
      abandons: ratingRow?.abandons ?? 0,
      gamesPlayed: ratingRow?.gamesPlayed ?? 0,
      matchesCreated: userRow.matchesCreated,
      successfulStarts: userRow.successfulStarts,
    };
  }

  async getPublicProfile(userId: string, viewerId?: string): Promise<PublicProfile | null> {
    const database = this.database;
    if (!database) return null;

    const [userRow] = await traceDbQuery(
      'db.users.select_public_profile',
      { operation: 'SELECT', table: 'users' },
      () =>
        database
          .select({
            id: users.id,
            gamertag: users.gamertag,
            suffix: users.suffix,
            elo: users.elo,
          })
          .from(users)
          .where(eq(users.id, userId))
          .limit(1),
    );
    if (!userRow) return null;

    const [ratingRow] = await traceDbQuery(
      'db.player_ratings.select_public_profile',
      { operation: 'SELECT', table: 'player_ratings' },
      () =>
        database
          .select()
          .from(playerRatings)
          .where(and(eq(playerRatings.userId, userId), eq(playerRatings.mode, 'pvp')))
          .limit(1),
    );

    const [followersCount, followingCount, followRecord] = await Promise.all([
      database.select({ count: count() }).from(userFollows).where(eq(userFollows.followingId, userId)),
      database.select({ count: count() }).from(userFollows).where(eq(userFollows.followerId, userId)),
      viewerId
        ? database
            .select({ count: count() })
            .from(userFollows)
            .where(and(eq(userFollows.followerId, viewerId), eq(userFollows.followingId, userId)))
        : Promise.resolve([{ count: 0 }]),
    ]);

    const recentResults = await traceDbQuery(
      'db.match_results.select_recent',
      { operation: 'SELECT', table: 'match_results' },
      () =>
        database
          .select({
            matchId: matchResults.matchId,
            result: matchResults.result,
            mode: matchResults.mode,
            completedAt: matchResults.createdAt,
            outcome: matches.outcome,
            player1Id: matches.player1Id,
            player2Id: matches.player2Id,
            player1Name: matches.player1Name,
            player2Name: matches.player2Name,
          })
          .from(matchResults)
          .leftJoin(matches, eq(matches.id, matchResults.matchId))
          .where(eq(matchResults.userId, userId))
          .orderBy(desc(matchResults.createdAt))
          .limit(8),
    );

    const openChallenges = await traceDbQuery(
      'db.matches.select_open_challenges',
      { operation: 'SELECT', table: 'matches' },
      () =>
        database
          .select({
            id: matches.id,
            createdAt: matches.createdAt,
            player1Id: matches.player1Id,
            player1Name: matches.player1Name,
            minPublicRating: matches.minPublicRating,
            maxPublicRating: matches.maxPublicRating,
            minGamesPlayed: matches.minGamesPlayed,
            requiresEstablishedRating: matches.requiresEstablishedRating,
          })
          .from(matches)
          .where(
            and(
              eq(matches.visibility, 'public_open'),
              eq(matches.publicStatus, 'open'),
              eq(matches.player1Id, userId),
            ),
          )
          .orderBy(desc(matches.createdAt)),
    );

    const row = ratingRow
      ? {
          eloRating: ratingRow.eloRating,
          glickoRating: ratingRow.glickoRating,
          glickoRatingDeviation: ratingRow.glickoRatingDeviation,
          glickoVolatility: ratingRow.glickoVolatility,
          gamesPlayed: ratingRow.gamesPlayed,
          wins: ratingRow.wins,
          losses: ratingRow.losses,
          draws: ratingRow.draws,
          abandons: ratingRow.abandons,
          provisional: ratingRow.provisional,
        }
      : null;
    const confidence = confidenceLabel(row, ratingRow?.lastRatedAt ?? null);

    const recentMatches: PublicMatchEntry[] = recentResults.map((entry) => {
      const outcome = entry.outcome as MatchOutcome | null;
      const opponentName =
        entry.player1Id === userId ? (entry.player2Name ?? null) : (entry.player1Name ?? null);
      return {
        matchId: entry.matchId,
        result: entry.result,
        mode: entry.mode as RatingMode,
        opponentName,
        completedAt: entry.completedAt.toISOString(),
        turnNumber: outcome?.turnNumber ?? null,
      };
    });

    const challenges: PublicChallengeEntry[] = openChallenges.map((challenge) => ({
      matchId: challenge.id,
      createdAt: challenge.createdAt.toISOString(),
      createdAtIso: challenge.createdAt.toISOString(),
      creatorName: challenge.player1Name ?? buildDisplayName(userRow.gamertag, userRow.suffix),
      creatorElo: userRow.elo,
      creatorRecord: {
        wins: row?.wins ?? 0,
        losses: row?.losses ?? 0,
        draws: row?.draws ?? 0,
        gamesPlayed: row?.gamesPlayed ?? 0,
        provisional: row?.provisional ?? true,
        confidenceLabel: confidence,
      },
      requirements: {
        minPublicRating: challenge.minPublicRating,
        maxPublicRating: challenge.maxPublicRating,
        minGamesPlayed: challenge.minGamesPlayed,
        requiresEstablishedRating: challenge.requiresEstablishedRating,
      },
    }));

    let streak = 0;
    for (const entry of recentMatches) {
      if (entry.result === 'draw') break;
      const sign = entry.result === 'win' ? 1 : -1;
      if (streak === 0 || Math.sign(streak) === sign) {
        streak += sign;
      } else {
        break;
      }
    }

    return {
      userId: userRow.id,
      gamertag: userRow.gamertag,
      displayName: buildDisplayName(userRow.gamertag, userRow.suffix),
      elo: userRow.elo,
      record: {
        wins: row?.wins ?? 0,
        losses: row?.losses ?? 0,
        draws: row?.draws ?? 0,
        gamesPlayed: row?.gamesPlayed ?? 0,
      },
      streak,
      confidenceLabel: confidence,
      recentMatches,
      openChallenges: challenges,
      followStats: {
        followers: followersCount[0]?.count ?? 0,
        following: followingCount[0]?.count ?? 0,
      },
      isFollowing: (followRecord[0]?.count ?? 0) > 0,
    };
  }
}

import type { FastifyInstance } from 'fastify';
import { z } from 'zod';
import { desc, eq } from 'drizzle-orm';
import { AchievementListSchema } from '@phalanxduel/shared';
import { ErrorResponseSchema } from '@phalanxduel/shared';
import { traceHttpHandler, httpTraceContext } from '../tracing.js';
import { toJsonSchema } from '../utils/openapi.js';
import { PlayerRatingsService } from '../ratings.js';
import { db } from '../db/index.js';
import { achievements } from '../db/schema.js';

export function registerProfileRoutes(fastify: FastifyInstance): void {
  const ratings = new PlayerRatingsService();

  const ProfileSchema = z.object({
    userId: z.uuid(),
    gamertag: z.string(),
    displayName: z.string(),
    elo: z.number().int(),
    record: z.object({
      wins: z.number().int(),
      losses: z.number().int(),
      draws: z.number().int(),
      gamesPlayed: z.number().int(),
    }),
    streak: z.number().int(),
    confidenceLabel: z.enum(['Provisional', 'Calibrating', 'Established', 'Inactive']),
    recentMatches: z.array(
      z.object({
        matchId: z.uuid(),
        result: z.enum(['win', 'loss', 'draw']),
        mode: z.enum(['pvp', 'sp-random', 'sp-heuristic']),
        opponentName: z.string().nullable(),
        completedAt: z.iso.datetime(),
        turnNumber: z.number().int().nullable(),
      }),
    ),
    openChallenges: z.array(
      z.object({
        matchId: z.uuid(),
        createdAt: z.iso.datetime(),
        createdAtIso: z.iso.datetime(),
        creatorName: z.string(),
        creatorElo: z.number().int(),
        creatorRecord: z.object({
          wins: z.number().int(),
          losses: z.number().int(),
          draws: z.number().int(),
          gamesPlayed: z.number().int(),
          provisional: z.boolean(),
          confidenceLabel: z.enum(['Provisional', 'Calibrating', 'Established', 'Inactive']),
        }),
        requirements: z.object({
          minPublicRating: z.number().int().nullable(),
          maxPublicRating: z.number().int().nullable(),
          minGamesPlayed: z.number().int().nullable(),
          requiresEstablishedRating: z.boolean(),
        }),
      }),
    ),
  });

  fastify.get<{ Params: { userId: string } }>(
    '/api/users/:userId/achievements',
    {
      schema: {
        tags: ['profiles'],
        summary: 'Get achievements for a user',
        params: toJsonSchema(z.object({ userId: z.uuid() })),
        response: {
          200: toJsonSchema(AchievementListSchema),
          404: toJsonSchema(ErrorResponseSchema),
        },
      },
    },
    async (request, reply) => {
      return traceHttpHandler('achievements.list', httpTraceContext(request, reply), async () => {
        const { userId } = request.params;
        if (!db) {
          void reply.status(503);
          return { error: 'Database unavailable', code: 'DB_UNAVAILABLE' };
        }
        const rows = await db
          .select()
          .from(achievements)
          .where(eq(achievements.userId, userId))
          .orderBy(desc(achievements.awardedAt));
        return {
          userId,
          achievements: rows.map((r) => ({
            id: r.id,
            userId: r.userId,
            type: r.type,
            awardedAt: r.awardedAt.toISOString(),
            matchId: r.matchId ?? null,
            metadata: r.metadata ?? {},
          })),
        };
      });
    },
  );

  fastify.get<{ Params: { userId: string } }>(
    '/api/profiles/:userId',
    {
      schema: {
        tags: ['profiles'],
        summary: 'Get a public player profile',
        description:
          'Returns a public read model derived from match results and player ratings without exposing raw Glicko internals.',
        params: toJsonSchema(
          z.object({
            userId: z.uuid(),
          }),
        ),
        response: {
          200: toJsonSchema(ProfileSchema),
          404: toJsonSchema(ErrorResponseSchema),
          503: toJsonSchema(ErrorResponseSchema),
        },
      },
    },
    async (request, reply) => {
      return traceHttpHandler('profiles.get', httpTraceContext(request, reply), async () => {
        const viewerId = (request.user as any)?.id;
        const profile = await ratings.getPublicProfile(request.params.userId, viewerId);
        if (!profile) {
          void reply.status(404);
          return { error: 'User not found', code: 'USER_NOT_FOUND' };
        }
        return profile;
      });
    },
  );
}

import type { FastifyInstance, FastifyRequest } from 'fastify';
import { z } from 'zod';
import { ErrorResponseSchema, SpectatorMatchSummarySchema } from '@phalanxduel/shared';
import { traceHttpHandler, httpTraceContext } from '../tracing.js';
import { toJsonSchema } from '../utils/openapi.js';
import { UserRepository } from '../db/user-repo.js';
import { MatchRepository } from '../db/match-repo.js';

export function registerSocialRoutes(fastify: FastifyInstance): void {
  const userRepo = new UserRepository();
  const matchRepo = new MatchRepository();

  const getAuthUser = async (request: FastifyRequest) => {
    try {
      let token = request.headers.authorization?.replace('Bearer ', '');
      token ??= (request as any).cookies?.phalanx_refresh;
      if (!token) return null;
      return fastify.jwt.verify<{ id: string; gamertag: string; suffix: number }>(token);
    } catch {
      return null;
    }
  };

  const CommentSchema = z.object({
    id: z.uuid(),
    userId: z.uuid(),
    gamertag: z.string(),
    avatarIcon: z.string().nullable(),
    content: z.string(),
    step: z.number().int().nullable(),
    createdAt: z.string().datetime(),
  });

  const MatchSocialStatsSchema = z.object({
    averageRating: z.number(),
    totalRatings: z.number().int(),
    favoriteCount: z.number().int(),
  });

  const FollowStatsSchema = z.object({
    followers: z.number().int(),
    following: z.number().int(),
  });

  // --- Follow Endpoints ---

  fastify.post<{ Params: { targetUserId: string } }>(
    '/api/users/:targetUserId/follow',
    {
      schema: {
        tags: ['social'],
        summary: 'Follow a user',
        params: toJsonSchema(z.object({ targetUserId: z.uuid() })),
        response: {
          204: { type: 'null', description: 'User followed successfully' },
          401: toJsonSchema(ErrorResponseSchema),
          404: toJsonSchema(ErrorResponseSchema),
        },
      },
    },
    async (request, reply) => {
      const user = await getAuthUser(request);
      if (!user) return reply.status(401).send({ error: 'Unauthorized', code: 'UNAUTHORIZED' });

      return traceHttpHandler('social.follow', httpTraceContext(request, reply), async () => {
        const followerId = user.id;
        const followingId = request.params.targetUserId;

        if (followerId === followingId) {
          void reply.status(400);
          return { error: 'Cannot follow yourself', code: 'SELF_FOLLOW_PROHIBITED' };
        }

        await userRepo.followUser(followerId, followingId);
        void reply.status(204);
        return null;
      });
    },
  );

  fastify.delete<{ Params: { targetUserId: string } }>(
    '/api/users/:targetUserId/follow',
    {
      schema: {
        tags: ['social'],
        summary: 'Unfollow a user',
        params: toJsonSchema(z.object({ targetUserId: z.uuid() })),
        response: {
          204: { type: 'null', description: 'User unfollowed successfully' },
